import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Read entire line

        char[] buffer = new char[10]; // Buffer size is limited to 10 characters

        // Copy user input into buffer with proper length checking
        for (int i = 0; i < Math.min(input.length(), buffer.length); i++) {
            buffer[i] = input.charAt(i);
        }

        // Ensure null-termination of the char array
        if (buffer.length > 0) {
            buffer[Math.min(buffer.length - 1, input.length())] = '\0';
        }

        // Print out the sanitized input
        System.out.println("Sanitized Input: " + new String(buffer).trim());
    }
}

